1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type Damage = {
9	  itemType: string;
10	  amount: number;
11	};
12	
13	export type Incident = {
14	  cause: string;
15	  damages: Damage[];
16	};
17	
18	export type QuoteStep = { op: "quote"; items: Item[] };
19	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
20	export type Step = QuoteStep | ClaimStep;
21	
22	export type Scenario = {
23	  customer: { yearsWithMHPCO: number };
24	  steps: Step[];
25	};
26	
27	export type QuoteResult = { premium: number };
28	export type ClaimResult = { payout: number; remainingCap: number };
29	export type StepResult = QuoteResult | ClaimResult;
30	
31	export type ScenarioResult = {
32	  results: StepResult[];
33	};
34	
35	const PROCESSING_FEE = 5;
36	const FIRST_INSURANCE_SURCHARGE = 0.1;
37	const LOYALTY_DISCOUNT = 0.2;
38	const LOYALTY_THRESHOLD_YEARS = 2;
39	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
40	const CURSED_SURCHARGE = 0.5;
41	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
42	const HIGH_ENCHANTMENT_THRESHOLD = 5;
43	const DEDUCTIBLE_PER_DAMAGE = 100;
44	const CAP_MULTIPLIER = 2;
45	const DAMAGE_HIGH_ENCHANT_THRESHOLD = 8;
46	const DAMAGE_HIGH_ENCHANT_RATE = 0.5;
47	
48	const ITEM_BASE_PREMIUM: Record<string, number> = {
49	  sword: 100,
50	  amulet: 60,
51	  rune: 25,
52	  moonstone: 25,
53	};
54	
55	const ITEM_INSURANCE_VALUE: Record<string, number> = {
56	  sword: 1000,
57	  amulet: 600,
58	  rune: 250,
59	};
60	
61	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
62	const COMPONENT_BLOCK_SIZE = 3;
63	const COMPONENT_BLOCK_PREMIUM = 60;
64	
65	const groupCountsByType = (items: Item[]): Map<string, number> => {
66	  const counts = new Map<string, number>();
67	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
68	  return counts;
69	};
70	
71	const basePremiumForGroup = (type: string, count: number): number => {
72	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
73	  return count * ITEM_BASE_PREMIUM[type];
74	};
75	
76	const sumBasePremium = (counts: Map<string, number>): number =>
77	  [...counts].reduce((total, [type, count]) => total + basePremiumForGroup(type, count), 0);
78	
79	const isHighlyEnchanted = (item: Item): boolean =>
80	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
81	
82	const surchargeRateForItem = (item: Item): number =>
83	  (item.cursed ? CURSED_SURCHARGE : 0) +
84	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
85	
86	const surchargeForItem = (item: Item): number =>
87	  ITEM_BASE_PREMIUM[item.type] * surchargeRateForItem(item);
88	
89	const itemSurcharges = (items: Item[]): number =>
90	  items.reduce((total, item) => total + surchargeForItem(item), 0);
91	
92	const calculatePremium = (
93	  items: Item[],
94	  yearsWithMHPCO: number,
95	  isFollowUpContract: boolean,
96	): number => {
97	  const base = sumBasePremium(groupCountsByType(items));
98	  const surcharges = itemSurcharges(items);
99	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE;
100	  const loyaltyDiscount =
101	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT : 0;
102	  const followUpDiscount = isFollowUpContract ? base * FOLLOWUP_CONTRACT_DISCOUNT : 0;
103	  return Math.ceil(
104	    base + surcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
105	  );
106	};
107	
108	type Policy = {
109	  items: Item[];
110	  remainingCap: number;
111	};
112	
113	const insuranceSum = (items: Item[]): number =>
114	  items.reduce((sum, item) => sum + ITEM_INSURANCE_VALUE[item.type], 0);
115	
116	const reimbursableAmount = (damage: Damage, item: Item): number =>
117	  (item.enchantment ?? 0) >= DAMAGE_HIGH_ENCHANT_THRESHOLD
118	    ? damage.amount * DAMAGE_HIGH_ENCHANT_RATE
119	    : damage.amount;
120	
121	const payoutForDamage = (damage: Damage, item: Item): number =>
122	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE_PER_DAMAGE);
123	
124	const findInsuredItem = (policy: Policy, itemType: string): Item =>
125	  policy.items.find((item) => item.type === itemType)!;
126	
127	const grossPayoutForIncident = (policy: Policy, incident: Incident): number =>
128	  incident.damages.reduce(
129	    (sum, damage) => sum + payoutForDamage(damage, findInsuredItem(policy, damage.itemType)),
130	    0,
131	  );
132	
133	const claimPayout = (policy: Policy, incident: Incident): number =>
134	  Math.floor(Math.min(grossPayoutForIncident(policy, incident), policy.remainingCap));
135	
136	const handleQuote = (
137	  step: QuoteStep,
138	  policies: Policy[],
139	  yearsWithMHPCO: number,
140	): QuoteResult => {
141	  const isFollowUpContract = policies.length >= 1;
142	  policies.push({ items: step.items, remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER });
143	  return { premium: calculatePremium(step.items, yearsWithMHPCO, isFollowUpContract) };
144	};
145	
146	const handleClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
147	  const policy = policies[step.policy];
148	  const payout = claimPayout(policy, step.incident);
149	  policy.remainingCap -= payout;
150	  return { payout, remainingCap: policy.remainingCap };
151	};
152	
153	export const runScenario = (scenario: Scenario): ScenarioResult => {
154	  const policies: Policy[] = [];
155	  const results: StepResult[] = scenario.steps.map((step) =>
156	    step.op === "quote"
157	      ? handleQuote(step, policies, scenario.customer.yearsWithMHPCO)
158	      : handleClaim(step, policies),
159	  );
160	  return { results };
161	};
